import sqlite3, re, json, csv
from collections import Counter, defaultdict
from pathlib import Path

# ----------------------------
# Lang detection from cards.cdb
# ----------------------------
def lang_from_cards_cdb(cards_cdb_path: str) -> str:
    p = Path(str(cards_cdb_path))
    folder = (p.parent.name or "").strip()
    low = folder.lower()

    # Common "xx-YY" or "xx_YY" locales (and variants like en-US_mdpro3)
    m = re.match(r"^([a-z]{2})[-_]", low)
    if m:
        return m.group(1)

    # If folder is already just "fr", "en", etc.
    m = re.match(r"^([a-z]{2})$", low)
    if m:
        return m.group(1)

    # Fallback: first two letters of whatever remains
    return (low[:2] if len(low) >= 2 else "fr")

# ============================================================
# 1) Detection + normalization (CN prompts in texts.str1..str16)
# ============================================================

# --- Core regexes (keep near the top) ---
_FLAG_RE = re.compile(r"(?:[\u4e00-\u9fff]|[「」『』？。！，：；…（）])")
_QUOTED_NAME_RE = re.compile(r"[「『][^」』]*[」』]")  # 「...」 or 『...』
_XYZ_DOUBLE_OVERLAY_CN_RE = re.compile(
    r"^是否在[「『][^」』]+[」』][「『][^」』]+[」』]超量怪兽上面重叠超量召唤[？?]$"
)

# --- CN “hint/prompt-ish” keyword detector (fast-path) ---
_SIMPLIFIED_HINT_RE = re.compile(
    r"(?:是否|这张|加入手卡|把卡|把怪兽|送去墓地|盖放|除外|检索|抽卡|特殊召唤|融合召唤|同调召唤|超量召唤|战斗阶段|结束阶段|里侧|守备|对方|自己|场上|卡组|墓地|无效"
    r"|属性|伤害|反转|回收|攻击上升|取除|指示物|魔力"
    r"|跳过|直接|攻击|选卡|卡片|装备|调整|同调|素材|选择|限制|回复|基本分|翻倍|等级|维持)"
)

def contains_cn_or_cn_punct(s: str) -> bool:
    """True if string contains CJK ideographs or CN/JP punctuation."""
    return isinstance(s, str) and bool(s) and bool(_FLAG_RE.search(s))

def contains_simplified_cn(s: str) -> bool:
    """Heuristic: prompt-ish simplified CN keywords (not a full CN detector)."""
    return isinstance(s, str) and bool(s) and bool(_SIMPLIFIED_HINT_RE.search(s))

def looks_like_effect_text(s: str) -> bool:
    """Guard: skip long PSCT-like effect bodies (we patch only UI prompts)."""
    if not isinstance(s, str) or not s:
        return False

    # Hard effect-body signals
    if "\n" in s:
        return True
    if "●" in s:
        return True

    # Very long = almost certainly effect text
    if len(s) >= 180:
        return True

    # Too much punctuation = usually effect-like
    punct = sum(s.count(x) for x in ["。", "；", ";", "：", ":", "，", ","])
    if punct >= 7:
        return True

    # Circled digits: only treat as effect-like if it looks like multi-item PSCT
    circled = sum(s.count(x) for x in "①②③④⑤⑥⑦⑧⑨")
    if circled >= 2 and len(s) >= 80:
        return True

    return False

def contains_untranslated_cn_prompt(s: str) -> bool:
    """
    Detection rule used by PatchMenu/reporting:
    - ignore effect-like text
    - flag prompt-ish simplified CN keywords (fast path)
    - also flag CN/JP-punct UI labels, including mixed CN+EN
    """
    if looks_like_effect_text(s):
        return False

    if contains_simplified_cn(s):
        return True

    if not contains_cn_or_cn_punct(s):
        return False

    # Mixed CN + Latin is *very often* exactly the “half translated” problem
    if re.search(r"[A-Za-z]", s):
        return True

    # For texts.str1..str16, allow longer “prompt-ish” labels than 24 chars
    L = len(s)
    if L <= 60:
        return True

    # Slightly longer, but still UI-ish if it looks like a prompt/question/label
    if L <= 90 and ("?" in s or "？" in s or ":" in s or "：" in s):
        return True

    return False
    
_TRAILING_PARENS_RE = re.compile(r"\(([^()]{1,32})\)$")

def _collapse_trailing_card_parens(s: str) -> str:
    """
    If a string ends with '(something)' and 'something' looks like a card-name placeholder,
    normalize it to '({CARD})' WITHOUT guessing the name.
    Idempotent: will not touch existing '({CARD})'.
    """
    m = _TRAILING_PARENS_RE.search(s)
    if not m:
        return s

    inner = m.group(1)
    if inner == "{CARD}" or "{CARD}" in inner:
        return s

    # Heuristic: short CJK token; avoid digits/latin and heavy punctuation.
    if re.search(r"[A-Za-z0-9]", inner):
        return s
    if not re.search(r"[\u4e00-\u9fff]", inner):
        return s
    if re.search(r"[。；;:：,，!?？]", inner):
        return s

    return s[:m.start()] + "({CARD})"

def normalize_cn_prompt(s: str) -> str:
    if not isinstance(s, str) or not s:
        return s

    s = (s.replace("？", "?")
           .replace("（", "(")
           .replace("）", ")")).strip()

    # If the whole string is exactly one quoted label, keep it literal
    # (prevents collisions like 「友情 YU-JYO」 vs 「团结 UNITY」)
    if _QUOTED_NAME_RE.fullmatch(s):
        return s

    s = _QUOTED_NAME_RE.sub("{CARD}", s)
    s = s.replace("{CARD}{CARD}", "{CARD}")
    s = _collapse_trailing_card_parens(s)
    return s.strip()


_DEFAULT_CANON_PAIRS = [
    # longest-first canonicalization (EN fragments -> CN baseline tokens) used for LOOKUP ONLY
    ("Spell/Trap Card", "魔法·陷阱卡"),
    ("Spell & Trap Card", "魔法·陷阱卡"),
    ("Spell/Trap", "魔法·陷阱卡"),
    ("Trap Card", "陷阱卡"),
    ("Spell Card", "魔法卡"),

    ("Negate the activation", "发动无效"),
    ("Negate the effect", "效果无效"),
    ("Negate", "无效"),
    ("Special Summon", "特殊召唤"),
    ("Add to hand", "加入手卡"),
    ("Send to the GY", "送去墓地"),
    ("Change Type", "改变种族"),
    ("Change Attribute", "改变属性"),
    ("Banish", "除外"),
    ("Destroy", "破坏"),
    ("Activate", "发动"),
    ("Set", "盖放"),
]

def canonicalize_for_lookup(s: str, canon_pairs) -> str:
    """
    Convert common EN UI fragments back into CN baseline tokens for lookup ONLY.
    This helps map mixed CN+EN cells onto CN baseline keys in a single pass.
    Longest-first; runs only when CJK is present.
    """
    if not isinstance(s, str) or not s:
        return s
    if not contains_cn_or_cn_punct(s):
        return s

    out = s
    for a, b in canon_pairs:
        out = out.replace(a, b)
    return out

